+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,9 +7768,43 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
+  if (!match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // Try to match select-based fabs: select (fcmp pred X, 0), X, (fneg X)
+    // or select (fcmp pred X, 0), (fneg X), X, or
+    // select any_cond, X, (fneg X) (for sign-insensitive predicates).
+    Value *CondVal, *TrueVal, *FalseVal;
+    if (!match(I.getOperand(0),
+               m_Select(m_Value(CondVal), m_Value(TrueVal), m_Value(FalseVal))))
+      return nullptr;
+
+    // Match select X, fneg X or select fneg X, X.
+    if (match(TrueVal, m_Value(X)) &&
+        match(FalseVal, m_FNeg(m_Specific(X)))) {
+      // TrueVal = X, FalseVal = fneg X
+    } else if (match(TrueVal, m_FNeg(m_Value(X))) &&
+               match(FalseVal, m_Specific(X))) {
+      // TrueVal = fneg X, FalseVal = X
+    } else {
+      return nullptr;
+    }

+    // If the condition is not an fcmp with X and 0, we can only fold
+    // for sign-insensitive predicates (equality/inequality/ord/uno).
+    FCmpInst::Predicate CondPred;
+    if (!match(CondVal, m_FCmp(CondPred, m_Specific(X), m_AnyZeroFP()))) {
+      switch (I.getPredicate()) {
+      default:
+        return nullptr;
+      case FCmpInst::FCMP_OEQ:
+      case FCmpInst::FCMP_UEQ:
+      case FCmpInst::FCMP_ONE:
+      case FCmpInst::FCMP_UNE:
+      case FCmpInst::FCMP_ORD:
+      case FCmpInst::FCMP_UNO:
+        break;
+      }
+    }
+  }
   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;

